100	const curseSurchargeForItem = (item: Item): number =>
101	  item.cursed ? basePremiumForType(item.type) * CURSE_SURCHARGE_RATE : 0;
102	
103	const enchantmentSurchargeForItem = (item: Item): number =>
104	  (item.enchantment ?? 0) >= ENCHANTMENT_SURCHARGE_THRESHOLD
105	    ? basePremiumForType(item.type) * ENCHANTMENT_SURCHARGE_RATE
106	    : 0;
107	
108	const totalItemSurcharge = (items: Item[]): number =>
109	  items.reduce(
110	    (total, item) =>
111	      total + curseSurchargeForItem(item) + enchantmentSurchargeForItem(item),
112	    0,
113	  );
114	
115	const policyDiscountRate = (customer: Customer, stepIndex: number): number => {
116	  const loyaltyDiscountRate =
117	    customer.yearsWithMHPCO >= LOYALTY_DISCOUNT_THRESHOLD_YEARS
118	      ? LOYALTY_DISCOUNT_RATE
119	      : 0;
120	  const followUpDiscountRate = stepIndex > 0 ? FOLLOW_UP_DISCOUNT_RATE : 0;
121	  return loyaltyDiscountRate + followUpDiscountRate;
122	};
123	
124	const payoutCapForItems = (items: Item[]): number =>
125	  PAYOUT_CAP_MULTIPLIER *
126	  items.reduce((total, item) => total + INSURANCE_VALUES[item.type], 0);
127	
128	const reimbursementRateForItem = (item: Item): number =>
129	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
130	    ? HIGH_ENCHANTMENT_REIMBURSEMENT_RATE
131	    : FULL_REIMBURSEMENT_RATE;
132	
133	const payoutForDamage = (damage: Damage, policyItems: Item[]): number => {
134	  const damagedItem = policyItems.find(
135	    (item) => item.type === damage.itemType,
136	  );
137	  if (damagedItem === undefined) {
138	    throw new Error(`Item type not covered by policy: ${damage.itemType}`);
139	  }
140	  return damage.amount * reimbursementRateForItem(damagedItem) - DEDUCTIBLE;
141	};
142	
143	const assertDamagesWithinCoverage = (
144	  damages: Damage[],
145	  policyItems: Item[],
146	): void => {
147	  const coveredCounts = countItemsByType(policyItems);
148	  const claimedCounts = countItemsByType(
149	    damages.map((damage) => ({ type: damage.itemType })),
150	  );
151	  for (const [type, claimed] of claimedCounts) {
152	    if (claimed > (coveredCounts.get(type) ?? 0)) {
153	      throw new Error(
154	        `More damage entries than covered items of type: ${type}`,
155	      );
156	    }
157	  }
158	};
159	
160	const incidentPayout = (incident: Incident, policyItems: Item[]): number => {
161	  assertDamagesWithinCoverage(incident.damages, policyItems);
162	  return Math.floor(
163	    incident.damages.reduce(
164	      (total, damage) => total + payoutForDamage(damage, policyItems),
165	      0,
166	    ),
167	  );
168	};
169	
170	const processClaimStep = (
171	  step: ClaimStep,
172	  steps: Step[],
173	  paidByPolicy: Map<number, number>,
174	): ClaimResult => {
175	  const policyItems = (steps[step.policy] as QuoteStep).items;
176	  const alreadyPaid = paidByPolicy.get(step.policy) ?? 0;
177	  const remainingCapBeforeClaim = payoutCapForItems(policyItems) - alreadyPaid;
178	  const payout = Math.min(
179	    incidentPayout(step.incident, policyItems),
180	    remainingCapBeforeClaim,
181	  );
182	  paidByPolicy.set(step.policy, alreadyPaid + payout);
183	  return {
184	    payout,
185	    remainingCap: remainingCapBeforeClaim - payout,
186	  };
187	};
188	
189	const processQuoteStep = (
190	  step: QuoteStep,
191	  customer: Customer,
192	  stepIndex: number,
193	): QuoteResult => {
194	  const totalBasePremium = calculateTotalBasePremium(step.items);
195	  const firstInsuranceSurcharge =
196	    totalBasePremium * FIRST_INSURANCE_SURCHARGE_RATE;
197	  const itemSurcharge = totalItemSurcharge(step.items);
198	  const discount =
199	    totalBasePremium * policyDiscountRate(customer, stepIndex);
200	  return {
201	    premium: Math.ceil(
202	      totalBasePremium + firstInsuranceSurcharge + itemSurcharge -
203	        discount + PROCESSING_FEE,
204	    ),
205	  };
206	};
207	
208	export const processScenario = (scenario: Scenario): ScenarioResult => {
209	  const paidByPolicy = new Map<number, number>();
210	  return {
211	    results: scenario.steps.map((step, index) =>
212	      "incident" in step
213	        ? processClaimStep(step, scenario.steps, paidByPolicy)
214	        : processQuoteStep(step, scenario.customer, index),
215	    ),
216	  };
217	};
